using Microsoft.ML.Data;

namespace ChurnPredictor.Models;

public class ChurnInput
{
    [LoadColumn(0)]
    public float Age { get; set; }

    [LoadColumn(1)]
    public float Income { get; set; }

    [LoadColumn(2)]
    public string Region { get; set; } = string.Empty;

    [LoadColumn(3)]
    public float PurchaseHistory { get; set; }

    [LoadColumn(4)]
    public string Churned { get; set; } = string.Empty;
}

public class ChurnPrediction
{
    [ColumnName("PredictedLabel")]
    public bool PredictedLabel { get; set; }

    public float Probability { get; set; }

    public float Score { get; set; }
}

using Microsoft.ML;
using Microsoft.ML.Data;
using ChurnPredictor.Models;

namespace ChurnPredictor.Services;

public static class ChurnModelTrainer
{
    public static void TrainAndSave(string dataPath, string modelPath, ILogger logger)
    {
        var mlContext = new MLContext(seed: 42);

        IDataView data = mlContext.Data.LoadFromTextFile<ChurnInput>(
            dataPath, hasHeader: true, separatorChar: ',');

        var split = mlContext.Data.TrainTestSplit(data, testFraction: 0.2);

        // Map "Yes"→true / "No"→false for the Label column
        var labelLookup = mlContext.Data.LoadFromEnumerable(new[]
        {
            new LabelMapping { Churned = "Yes", Label = true },
            new LabelMapping { Churned = "No", Label = false },
        });

        var pipeline = mlContext.Transforms.Conversion.MapValue(
                outputColumnName: "Label",
                lookupMap: labelLookup,
                keyColumn: nameof(LabelMapping.Churned),
                valueColumn: nameof(LabelMapping.Label),
                inputColumnName: nameof(ChurnInput.Churned))
            .Append(mlContext.Transforms.Categorical.OneHotEncoding("RegionEncoded", nameof(ChurnInput.Region)))
            .Append(mlContext.Transforms.Concatenate("Features",
                nameof(ChurnInput.Age),
                nameof(ChurnInput.Income),
                "RegionEncoded",
                nameof(ChurnInput.PurchaseHistory)))
            .Append(mlContext.BinaryClassification.Trainers.SdcaLogisticRegression());

        var model = pipeline.Fit(split.TrainSet);

        IDataView predictions = model.Transform(split.TestSet);
        CalibratedBinaryClassificationMetrics metrics =
            mlContext.BinaryClassification.Evaluate(predictions);

        logger.LogInformation(
            "Model metrics — AUC: {Auc:F4}, F1: {F1:F4}, Accuracy: {Accuracy:F4}",
            metrics.AreaUnderRocCurve, metrics.F1Score, metrics.Accuracy);

        mlContext.Model.Save(model, data.Schema, modelPath);
        logger.LogInformation("Model saved to {ModelPath}", modelPath);
    }

    private sealed class LabelMapping
    {
        public string Churned { get; set; } = string.Empty;
        public bool Label { get; set; }
    }
}

