using Microsoft.Extensions.ML;
using ChurnPredictor.Models;
using ChurnPredictor.Services;

var builder = WebApplication.CreateBuilder(args);

var dataPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "customers.csv");
var modelPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "ChurnModel.zip");

// Train and save the model at startup
ChurnModelTrainer.TrainAndSave(dataPath, modelPath, builder.Services.BuildServiceProvider().GetRequiredService<ILogger<Program>>());

builder.Services.AddPredictionEnginePool<ChurnInput, ChurnPrediction>()
    .FromFile(modelPath);

var app = builder.Build();

app.MapGet("/", () => "Hello");

app.MapPost("/predict", (PredictionEnginePool<ChurnInput, ChurnPrediction> pool, ChurnPredictRequest request) =>
{
    var input = new ChurnInput
    {
        Age = request.Age,
        Income = request.Income,
        Region = request.Region,
        PurchaseHistory = request.PurchaseHistory,
    };

    var prediction = pool.Predict(input);

    return Results.Ok(new
    {
        WillChurn = prediction.PredictedLabel,
        prediction.Probability,
        prediction.Score,
    });
});

app.Run();

public record ChurnPredictRequest(float Age, float Income, string Region, float PurchaseHistory);

